<span class="line"><span class="token class-name"><span class="token keyword">string</span></span> list <span class="token operator">=</span> <span class="token keyword">string</span><span class="token punctuation">.</span><span class="token function">Join</span><span class="token punctuation">(</span><span class="token string">&quot;, &quot;</span><span class="token punctuation">,</span> parts<span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">// 2024, 01, 15</span></span>
